interface Item {
  type: string;
  material: string;
  enchantment: number;
  cursed: boolean;
}

interface QuoteStep {
  op: "quote";
  items: Item[];
}

interface ClaimStep {
  op: "claim";
  policy: number;
  incident: {
    cause: string;
    damages: { itemType: string; amount: number }[];
  };
}

type Step = QuoteStep | ClaimStep;

interface Scenario {
  customer: { yearsWithMHPCO: number };
  steps: Step[];
}

interface QuoteResult {
  premium: number;
}

interface ClaimResult {
  payout: number;
  remainingCap: number;
}

interface ScenarioOutput {
  results: (QuoteResult | ClaimResult)[];
}

const FIRST_INSURANCE_SURCHARGE_PERCENT = 10;
const PROCESSING_FEE = 5;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
};

export const processScenario = (scenario: Scenario): ScenarioOutput => {
  const results = scenario.steps.map((step) => {
    const basePremium = (step as QuoteStep).items.reduce(
      (sum, item) => sum + BASE_PREMIUMS[item.type],
      0
    );
    const premium =
      Math.ceil((basePremium * (100 + FIRST_INSURANCE_SURCHARGE_PERCENT)) / 100) +
      PROCESSING_FEE;
    return { premium };
  });
  return { results };
};

