  op: "quote";
  items: Item[];
}

interface ClaimStep {
  op: "claim";
  policy: number;
  incident: {
    cause: string;
    damages: { itemType: string; amount: number }[];
  };
}

type Step = QuoteStep | ClaimStep;

interface Scenario {
  customer: { yearsWithMHPCO: number };
  steps: Step[];
}

interface QuoteResult {
  premium: number;
}

interface ClaimResult {
  payout: number;
  remainingCap: number;
}

interface ScenarioOutput {
  results: (QuoteResult | ClaimResult)[];
}

const FIRST_INSURANCE_SURCHARGE_PERCENT = 10;
const PROCESSING_FEE = 5;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const COMPONENT_PREMIUM = 25;
const BUILDING_BLOCK_PREMIUM = 60;

export const processScenario = (scenario: Scenario): ScenarioOutput => {
  const results = scenario.steps.map((step) => {
    const items = (step as QuoteStep).items;
    const counts: Record<string, number> = {};
    for (const item of items) {
      counts[item.type] = (counts[item.type] || 0) + 1;
    }

    let basePremium = 0;
    for (const [type, count] of Object.entries(counts)) {
      if (type in BASE_PREMIUMS) {
        basePremium += count * BASE_PREMIUMS[type];
      } else {
        const blocks = Math.floor(count / 3);
        const remaining = count % 3;
        basePremium += blocks * BUILDING_BLOCK_PREMIUM + remaining * COMPONENT_PREMIUM;
      }
    }
    const premium =
      Math.ceil((basePremium * (100 + FIRST_INSURANCE_SURCHARGE_PERCENT)) / 100) +
      PROCESSING_FEE;
    return { premium };
  });
  return { results };
};

