import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("Quoting", () => {
    it("should calculate base premium for a single sword with first insurance surcharge and processing fee", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "sword", material: "steel", enchantment: 3, cursed: false },
            ],
          },
        ],
      });

      expect(result).toEqual({
        results: [{ premium: 115 }],
      });
    });
    it("should calculate base premium for each main item type", () => {
      const amuletResult = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "amulet", material: "silver", enchantment: 0, cursed: false },
            ],
          },
        ],
      });
      expect(amuletResult).toEqual({ results: [{ premium: 71 }] });

      const staffResult = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "staff", material: "wood", enchantment: 0, cursed: false },
            ],
          },
        ],
      });
      expect(staffResult).toEqual({ results: [{ premium: 93 }] });

      const potionResult = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "potion", material: "glass", enchantment: 0, cursed: false },
            ],
          },
        ],
      });
      expect(potionResult).toEqual({ results: [{ premium: 49 }] });
    });
    it("should sum premiums for multiple items in one quote", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "sword", material: "steel", enchantment: 0, cursed: false },
              { type: "amulet", material: "silver", enchantment: 0, cursed: false },
            ],
          },
        ],
      });

      expect(result).toEqual({
        results: [{ premium: 181 }],
      });
    });
    it("should calculate premium for a single component", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "rune", material: "stone", enchantment: 0, cursed: false },
            ],
          },
        ],
      });

      expect(result).toEqual({
        results: [{ premium: 33 }],
      });
    });
    it("should apply building block pricing for 3 alike components", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "rune", material: "stone", enchantment: 0, cursed: false },
              { type: "rune", material: "stone", enchantment: 0, cursed: false },
              { type: "rune", material: "stone", enchantment: 0, cursed: false },
            ],
          },
        ],
      });

      expect(result).toEqual({
        results: [{ premium: 71 }],
      });
    });
    it("should apply 50% cursed item surcharge", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "sword", material: "steel", enchantment: 0, cursed: true },
            ],
          },
        ],
      });

      expect(result).toEqual({
        results: [{ premium: 170 }],
      });
    });
    it("should apply 30% surcharge for enchantment level >= 5", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "staff", material: "wood", enchantment: 5, cursed: false },
            ],
          },
        ],
      });

      expect(result).toEqual({
        results: [{ premium: 120 }],
      });
    });
    it.todo("should apply 20% loyalty discount for customers with >= 2 years");
    it.todo("should apply 15% multi-contract discount on subsequent quotes");
  });

  describe("Claims", () => {
    it.todo("should apply 100G deductible to a basic claim");
    it.todo("should cap total payout at twice the insurance sum");
    it.todo("should reimburse at 50% for items with enchantment >= 8");
    it.todo("should fully reimburse damage to dragon material items");
    it.todo("should track remaining cap across multiple claims on same policy");
  });
});

