export const processScenario = (scenario: Scenario): ScenarioOutput => {
  const { yearsWithMHPCO } = scenario.customer;
  const results = scenario.steps.map((step) => {
    const itemPremiums = calculateItemPremiums((step as QuoteStep).items);
    let adjusted = itemPremiums;

    if (yearsWithMHPCO === 0) {
      adjusted = Math.ceil((adjusted * (100 + FIRST_INSURANCE_SURCHARGE_PERCENT)) / 100);
