    if (yearsWithMHPCO >= 2) {
      adjusted = adjusted - Math.floor((adjusted * LOYALTY_DISCOUNT_PERCENT) / 100);
    }

    const premium = adjusted + PROCESSING_FEE;
    return { premium };
  });
  return { results };
};

