            op: "quote" as const,
            items: [
              { type: "sword", material: "steel", enchantment: 8, cursed: false },
            ],
          },
          {
            op: "claim" as const,
            policy: 0,
            incident: {
              cause: "tavern brawl",
              damages: [{ itemType: "sword", amount: 400 }],
            },
          },
        ],
      });

      expect(result).toEqual({
        results: [
          { premium: 148 },
          { payout: 100, remainingCap: 1900 },
        ],
      });
    });
    it("should fully reimburse damage to dragon material items", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "sword", material: "dragon", enchantment: 8, cursed: false },
            ],
          },
          {
            op: "claim" as const,
            policy: 0,
            incident: {
              cause: "goblin raid",
              damages: [{ itemType: "sword", amount: 400 }],
            },
          },
        ],
      });

      expect(result).toEqual({
        results: [
          { premium: 148 },
          { payout: 300, remainingCap: 1700 },
        ],
      });
    });
    it.todo("should track remaining cap across multiple claims on same policy");
  });
});

